        and pg_get_constraintdef(oid) = 'UNIQUE (tenant_id, legacy_class_id)'
    ),
    coalesce((
      select conname
      from pg_constraint
      where conrelid = 'public.classes'::regclass
        and contype = 'u'
        and pg_get_constraintdef(oid) = 'UNIQUE (tenant_id, legacy_class_id)'
