        and tgname = 'sync_classes_legacy_columns'
        and not tgisinternal
    ),
    coalesce((
      select pg_get_triggerdef(oid)
      from pg_trigger
      where tgrelid = 'public.classes'::regclass
        and tgname = 'sync_classes_legacy_columns'
    ), 'missing')::text
